#!/usr/bin/env bash
# Fast Chronos2 hyperparam search for all symbols with training data.
# Uses a small candidate grid (6 configs) instead of 48-eval DIRECT search.
# Each symbol takes ~60-90s. Skips symbols that already have calibrated configs
# (ones not generated by generate_default_hyperparams.py).
#
# Grid covers key dimensions:
#   context_length: 512, 1024, 2048
#   use_multivariate: true, false
#   scaler: none
#   batch_size: 128
#
# Run after generate_default_hyperparams.py and after preaug sweep (optional).
#
# Usage:
#   bash scripts/run_hyperparams_fast.sh              # all symbols
#   bash scripts/run_hyperparams_fast.sh 0 500        # symbols 0-499
#   bash scripts/run_hyperparams_fast.sh 500 1000     # next batch

set -euo pipefail
cd "$(dirname "$0")/.."
source .venv/bin/activate 2>/dev/null || true

SKIP="${1:-0}"
LIMIT="${2:-0}"
HP_DIR="hyperparams/chronos2"
DATA_DIR="trainingdata"
OUT_DIR="chronos2_benchmarks/fast_search"

mkdir -p "$OUT_DIR"

# Only process symbols that have default configs (source=generate_default_hyperparams)
# Skip those already calibrated by benchmark_chronos2.py (source=chronos2_benchmark)
mapfile -t ALL_SYMS < <(
  for hp_file in "$HP_DIR"/*.json; do
    sym="$(basename "$hp_file" .json)"
    # Check if it's a default config (not yet calibrated)
    source_val=$(python3 -c "
import json, sys
try:
    d = json.loads(open('$hp_file').read())
    print(d.get('metadata', {}).get('source', 'unknown'))
except:
    print('unknown')
" 2>/dev/null)
    if [ "$source_val" = "generate_default_hyperparams" ]; then
      if [ -f "$DATA_DIR/${sym}.csv" ]; then
        echo "$sym"
      fi
    fi
  done | sort
)

TOTAL=${#ALL_SYMS[@]}
echo "Symbols needing hyperparam calibration: $TOTAL"

if [ "$SKIP" -gt 0 ]; then
  ALL_SYMS=("${ALL_SYMS[@]:$SKIP}")
fi
if [ "$LIMIT" -gt 0 ]; then
  ALL_SYMS=("${ALL_SYMS[@]:0:$LIMIT}")
fi

echo "Processing ${#ALL_SYMS[@]} symbols (skip=$SKIP limit=$LIMIT)"
echo ""

DONE=0
TOTAL_THIS_RUN=${#ALL_SYMS[@]}

for sym in "${ALL_SYMS[@]}"; do
  DONE=$((DONE + 1))
  echo "[${DONE}/${TOTAL_THIS_RUN}] $sym — running fast hyperparam grid..."
  python3 benchmark_chronos2.py \
    --symbols "$sym" \
    --search-method direct \
    --auto-context-lengths \
    --auto-context-min 256 \
    --auto-context-max 2048 \
    --auto-context-step 512 \
    --direct-maxfun 8 \
    --direct-maxiter 20 \
    --scalers none \
    --multivariate-modes true false \
    --update-hyperparams \
    --hyperparam-root hyperparams \
    --output-dir "$OUT_DIR" \
    2>&1 | grep -E "^\[INFO\]|best=|val_pct_mae|ERROR" | tail -5 || true
done

echo ""
echo "=== Fast hyperparam search complete: $DONE symbols ==="
echo "Updated configs in $HP_DIR"
